-- ============================================================================
-- Supplier material price book — real wholesale gear + prices (goelectrical.com.au)
-- used to cost the material side of a design/quote (BOM), separate from the
-- installer labour price_books. Prices are ex-GST AUD per unit, 4-dp to match
-- the supplier. category drives which lines a design pulls (panel/inverter/
-- battery/mounting/…); spec carries the sizing facts the estimate reads
-- (watts, kw, kwh, phase). Idempotent: re-running upserts price + on_hand so we
-- can refresh the catalog as new supplier exports arrive.
-- ============================================================================
create table if not exists public.supplier_materials (
  id uuid primary key default gen_random_uuid(),
  supplier      text not null default 'goelectrical',
  brand         text,
  category      text not null,            -- panel|inverter|battery|mounting|cable|conduit|meter|gateway|ct|camera|accessory
  part_no       text not null,            -- supplier P/N
  description   text not null,
  unit          text not null default 'EA',
  unit_price    numeric(12,4),            -- ex-GST AUD/unit; null = request-a-quote
  currency      text not null default 'AUD',
  spec          jsonb not null default '{}'::jsonb,  -- {watts,kw,kwh,phase,hybrid,...}
  on_hand       int,
  url           text,
  active        boolean not null default true,
  captured_at   timestamptz not null default now(),
  unique (supplier, part_no)
);

alter table public.supplier_materials enable row level security;

drop policy if exists supplier_materials_read on public.supplier_materials;
create policy supplier_materials_read on public.supplier_materials
  for select using (public.is_active_staff() or public.is_admin());

drop policy if exists supplier_materials_write on public.supplier_materials;
create policy supplier_materials_write on public.supplier_materials
  for all using (public.is_admin()) with check (public.is_admin());

-- ---------------------------------------------------------------------------
-- Seed / refresh catalog (idempotent upsert on supplier+part_no)
-- ---------------------------------------------------------------------------
